+export function pushIndentedBlock(lines: string[], text: string): void {
+  const normalized = normalizeContentText(text);
+  if (!normalized) {
+    return;
+  }
+
+  for (const line of normalized.split("\n")) {
+    lines.push(`   ${line}`);
+  }
